class TestUrlUtils:
    def test_adds_https_when_missing(self):
        assert UrlUtils.add_https_if_missing("foo.example.com") == "https://foo.example.com"

    def test_leaves_https_unchanged(self):
        assert UrlUtils.add_https_if_missing("https://foo.com") == "https://foo.com"

    def test_leaves_http_unchanged(self):
        assert UrlUtils.add_https_if_missing("http://foo.com") == "http://foo.com"


